class Solution {
public:
    bool canSegmentString(string inputString, vector<string>& dictionaryWords) {
        unordered_set<string> dict(dictionaryWords.begin(), dictionaryWords.end());
        int n = inputString.size();

        vector<bool> dp(n + 1, false);
        dp[0] = true;  // empty string is segmentable

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                if (dp[j] && dict.count(inputString.substr(j, i - j))) {
                    dp[i] = true;
                    break;
                }
            }
        }
        return dp[n];
    }
};

