#define MAX_LEN 305

int isInDictionary(char *s, int l, int r, char dict[][MAX_WORD], int dictSize) {
    char temp[MAX_WORD];
    int len = r - l;

    for (int i = 0; i < dictSize; i++) {
        if ((int)strlen(dict[i]) == len) {
            strncpy(temp, s + l, len);
            temp[len] = '\0';
            if (strcmp(temp, dict[i]) == 0)
                return 1;
        }
    }
    return 0;
}

/* Core Solution Function */
int canSegmentString(char *inputString, char dict[][MAX_WORD], int dictSize) {
    int n = strlen(inputString);
    int dp[MAX_LEN] = {0};

    dp[0] = 1; // empty string

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < i; j++) {
            if (dp[j] && isInDictionary(inputString, j, i, dict, dictSize)) {
                dp[i] = 1;
                break;
            }
        }
    }
    return dp[n];
}

