class Solution {

    public boolean canSegmentString(String inputString, List<String> dictionaryWords) {
        Set<String> dict = new HashSet<>(dictionaryWords);
        int n = inputString.length();

        boolean[] dp = new boolean[n + 1];
        dp[0] = true; // empty string is segmentable

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                if (dp[j] && dict.contains(inputString.substring(j, i))) {
                    dp[i] = true;
                    break;
                }
            }
        }
        return dp[n];
    }
}

